 public function definitions():array{$s=fn(mixed$d='',bool$p=true)=>['type'=>'string','default'=>$d,'public'=>$p];$b=fn(bool$d,bool$p=true)=>['type'=>'boolean','default'=>$d,'public'=>$p];$i=fn(int$d,bool$p=true)=>['type'=>'integer','default'=>$d,'public'=>$p];$n=fn(float$d,bool$p=true)=>['type'=>'decimal','default'=>$d,'public'=>$p];return[
 'shop'=>['shop_name'=>$s('MH Mini Mart'),'logo'=>$s(''),'address'=>$s(''),'phone'=>$s(''),'email'=>$s(''),'registration_number'=>$s(''),'default_customer_name'=>$s('Walk-in Customer'),'receipt_footer'=>$s('Thank you for shopping with us.'),'return_policy'=>$s('Please keep your receipt for returns.')],
 'localization'=>['currency_code'=>$s('PKR'),'currency_symbol'=>$s('Rs.'),'currency_position'=>$s('before'),'decimal_places'=>$i(2),'thousand_separator'=>$s(','),'decimal_separator'=>$s('.'),'timezone'=>$s('Asia/Karachi'),'date_format'=>$s('d-m-Y'),'time_format'=>$s('12'),'first_day_of_week'=>$s('monday')],
 'tax'=>['enabled'=>$b(false),'name'=>$s('Tax'),'percentage'=>$n(0),'calculation_mode'=>$s('after_discount'),'show_on_receipt'=>$b(true)],
 'discounts'=>['enabled'=>$b(true),'default_type'=>$s('fixed'),'default_value'=>$n(0),'maximum_cashier_discount'=>$n(10),'allow_cashier_discounts'=>$b(true),'require_admin_above_limit'=>$b(true)],
 'inventory'=>['global_tracking_enabled'=>$b(true),'default_minimum_stock'=>$n(5),'allow_negative_stock'=>$b(false),'low_stock_alerts'=>$b(true),'out_of_stock_alerts'=>$b(true),'wastage_tracking'=>$b(true),'expiry_tracking'=>$b(false)],
